// ═══════════════════════════════════════════════════════
// Step 6: Parse RAG + Build LLM Comparison Request
// Generisch: Verwendet Config fuer Firmennamen und Modell
// Das LLM extrahiert Mitbewerber-Infos AUS DEM RAG
// ═══════════════════════════════════════════════════════
const ragResp = $input.item.json;
const fact = $('04 - Build RAG Request').item.json;
const config = fact.config;

const docs = ragResp.documents?.[0] || [];
const metas = ragResp.metadatas?.[0] || [];
const dists = ragResp.distances?.[0] || [];

const contextChunks = docs.map((text, i) => {
  const meta = metas[i] || {};
  const source = (meta.name || meta.source || 'Unbekannt')
    .replace(/\.md\.txt$|\.txt$|\.md$/gi, '').replace(/_/g, ' ').trim();
  const dist = dists[i] || 'N/A';
  return '### Chunk ' + (i+1) + ' (Quelle: ' + source + ', Distance: ' + (typeof dist === 'number' ? dist.toFixed(3) : dist) + ')\n' + text;
}).join('\n\n');

const systemPrompt = `Du bist ein Versicherungsexperte, der AVB (Allgemeine Versicherungsbedingungen) analysiert und vergleicht.

Deine Aufgabe: Analysiere die bereitgestellten ${config.competitorName} AVB-Dokumente zu einem bestimmten Aspekt und vergleiche das Ergebnis mit der ${config.ownCompanyName} ${config.ownProductName}.

## WICHTIGE REGELN:
1. Extrahiere die ${config.competitorShort}-Informationen AUSSCHLIESSLICH aus den bereitgestellten RAG-Dokumenten
2. Wenn die Dokumente KEINE Information zu diesem Aspekt enthalten, schreibe klar: "In den vorliegenden ${config.competitorShort} AVB wurde hierzu keine Regelung gefunden."
3. ERFINDE KEINE Informationen - nur was in den Dokumenten steht
4. Sei praezise: Nenne konkrete Betraege, Prozentsaetze, Bedingungen, Paragraphen
5. Zitiere relevante Passagen aus den Dokumenten
6. Bewerte am Ende: Welcher Anbieter bietet hier den besseren Schutz? (${config.ownCompanyShort} besser / ${config.competitorShort} besser / gleichwertig / nicht vergleichbar)
7. Antworte auf Deutsch in strukturierter Form

## Bereitgestellte ${config.competitorShort} AVB-Dokumente:
` + contextChunks;

const userPrompt = `Analysiere und vergleiche folgenden Aspekt:

**Kategorie:** ${fact.kategorie}
**Aspekt:** ${fact.aspekt}

**${config.ownCompanyName} (${config.ownCompanyShort}) Regelung:**
${fact.own_data}

**Frage an die ${config.competitorShort} AVB:**
${fact.rag_query}

Bitte:
1. Was genau sagen die ${config.competitorShort} AVB-Dokumente zu diesem Aspekt? Zitiere relevante Stellen.
2. Fasse die ${config.competitorShort}-Regelung in 1-3 Saetzen zusammen
3. Vergleiche mit der ${config.ownCompanyShort}-Regelung: Was sind die konkreten Unterschiede?
4. Bewertung: Wer bietet den besseren Schutz fuer diesen Aspekt?`;

return {
  ...fact,
  ragContext: contextChunks,
  ragChunkCount: docs.length,
  ragDistances: dists.filter(d => typeof d === 'number').map(d => d.toFixed(3)),
  requestBody: JSON.stringify({
    model: config.llmModel,
    messages: [
      { role: 'system', content: systemPrompt },
      { role: 'user', content: userPrompt }
    ],
    temperature: 0.2,
    max_tokens: 1200,
    stream: false
  })
};
